17	const willSurviveToNextGeneration = (isAlive: boolean, neighbors: number): boolean => {
18	  if (isAlive && neighbors < 2) {
19	    return false; // Underpopulation rule
20	  }
21	  if (isAlive && neighbors > 3) {
22	    return false; // Overpopulation rule
23	  }
24	  if (isAlive && (neighbors === 2 || neighbors === 3)) {
25	    return true; // Survival rule
26	  }
27	  if (!isAlive && neighbors === 3) {
28	    return true; // Reproduction rule
29	  }
30	  return isAlive; // Default: cell stays as is
31	};
32	
33	export function nextGeneration(grid: Grid): Grid {
34	  if (grid.length === 0) {
35	    return [];
36	  }
37	
38	  return grid.map((row, rowIdx) =>
39	    row.map((cell, colIdx) => {
40	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
41	      return willSurviveToNextGeneration(cell, neighbors);
42	    })
43	  );
44	}
